import sqlite3

def search(fields):
    conn = sqlite3.connect('database.db')
    cursor = conn.cursor()

    query = "SELECT * FROM table WHERE "
    conditions = []

    for field in fields:
        if field['op'] == '=':
            op = ' = ? '
        elif field['op'] == '>':
            op = ' > ? '
        elif field['op'] == '<':
            op = ' < ? '
        elif field['op'] == 'LIKE':
            op = ' LIKE ? '

        conditions.append(f"{field['field']} {op}")

    query += " AND ".join(conditions)

    cursor.execute(query, [value for field in fields for value in (field['value'],)])

    results = cursor.fetchall()
    conn.close()

    return results

